PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?skyscraper ?skyscraperLabel ?commissioner ?commissionerLabel ?inception WHERE {
  ?skyscraper wdt:P31 / wdt:P279 * wd:Q11303 ; wdt:P2044 ?height .
  BIND(xsd:decimal(REPLACE(STR(?height) , "[^0-9.]+" , "")) AS ?h)
  FILTER(?h > 500)
  OPTIONAL {
    ?skyscraper wdt:P88 ?commissioner .
  }
  OPTIONAL {
    ?skyscraper wdt:P571 ?inception .
  }
  OPTIONAL {
    ?skyscraper rdfs:label ?skyscraperLabel
    FILTER(lang(?skyscraperLabel) = "en")
    .
  }
  OPTIONAL {
    ?commissioner rdfs:label ?commissionerLabel
    FILTER(lang(?commissionerLabel) = "en")
    .
  }
}
ORDER BY DESC(?h)
LIMIT 10

